create extension if not exists "uuid-ossp";
create table if not exists products (id uuid primary key default uuid_generate_v4(),sku text unique not null,brand text,category text,season text default 'Ganzjährig',size text,color text,material text,condition text,status text default 'Entwurf',purchase_price numeric(10,2),sale_price numeric(10,2),discount_percent numeric(5,2) default 0,target_country text,sales_channel text,designer_level text,authenticity_status text,notes text,trend_score numeric(5,2) default 50,storage_location text,purchase_source text,sold_at date,created_at timestamptz default now(),updated_at timestamptz default now());
alter table products add column if not exists season text default 'Ganzjährig';alter table products add column if not exists discount_percent numeric(5,2) default 0;alter table products add column if not exists trend_score numeric(5,2) default 50;alter table products add column if not exists storage_location text;alter table products add column if not exists purchase_source text;alter table products add column if not exists sold_at date;alter table products add column if not exists updated_at timestamptz default now();
create table if not exists expenses (id uuid primary key default uuid_generate_v4(),expense_date date not null default current_date,category text,description text,supplier text,invoice_number text,net_amount numeric(10,2),vat_rate numeric(5,2) default 19,gross_amount numeric(10,2),payment_method text,receipt_available boolean default false,tax_deductible text default 'prüfen',recurring text default 'einmalig',notes text,created_at timestamptz default now(),updated_at timestamptz default now());
alter table expenses add column if not exists updated_at timestamptz default now();
alter table products enable row level security;alter table expenses enable row level security;
drop policy if exists "products_select_public" on products;create policy "products_select_public" on products for select using (true);drop policy if exists "products_insert_public" on products;create policy "products_insert_public" on products for insert with check (true);drop policy if exists "products_update_public" on products;create policy "products_update_public" on products for update using (true) with check (true);drop policy if exists "products_delete_public" on products;create policy "products_delete_public" on products for delete using (true);
drop policy if exists "expenses_select_public" on expenses;create policy "expenses_select_public" on expenses for select using (true);drop policy if exists "expenses_insert_public" on expenses;create policy "expenses_insert_public" on expenses for insert with check (true);drop policy if exists "expenses_delete_public" on expenses;create policy "expenses_delete_public" on expenses for delete using (true);
grant usage on schema public to anon;grant select, insert, update, delete on table products to anon;grant select, insert, delete on table expenses to anon;
update products set updated_at=now() where updated_at is null;update products set season='Ganzjährig' where season is null;update products set discount_percent=0 where discount_percent is null;update products set trend_score=50 where trend_score is null;notify pgrst, 'reload schema';
alter table products add column if not exists style_key text;
alter table products add column if not exists pattern text;
alter table products add column if not exists occasion text;
alter table products add column if not exists era text;
alter table products add column if not exists rarity text;
notify pgrst, 'reload schema';
